const response = $('Create Parent Issue').item.json;

if (!response?.data?.issueCreate?.issue?.id) {
  throw new Error('Linear rejected the mutation: ' + JSON.stringify(response));
}

const parentIssueId = response.data.issueCreate.issue.id;
const videos = $('Webhook').item.json.body.videos;

return videos.map(v => ({
  json: {
    parentId: parentIssueId,
    videoNumber: v.number,
    mainCam: v.main_cam
  }
}));

const url = $json.mainCam || '';
const match = url.match(/\/file\/d\/([a-zA-Z0-9_-]+)/);
if (!match) {
  throw new Error('Cannot extract Google Drive file ID from: ' + url);
}
return [{ json: { ...$json, fileId: match[1] } }];

const binary = $input.item.binary?.data;
if (!binary) {
  return [{ json: { ...$('Extract Drive File ID').item.json, skipTranscription: true, skipReason: 'no_binary' } }];
}

const sizeStr = binary.fileSize || '0';
const match = sizeStr.match(/([\d.]+)\s*(kB|MB|GB)/i);
if (!match) {
  return [{ json: { ...$('Extract Drive File ID').item.json, skipTranscription: true, skipReason: 'unknown_size' } }];
}

const num = parseFloat(match[1]);
const unit = match[2].toUpperCase();
let bytes = num;
if (unit === 'KB') bytes = num * 1024;
if (unit === 'MB') bytes = num * 1024 * 1024;
if (unit === 'GB') bytes = num * 1024 * 1024 * 1024;

// Whisper hard limit is 25MB
if (bytes >= 26214400) {
  return [{ json: { ...$('Extract Drive File ID').item.json, skipTranscription: true, skipReason: 'file_too_large' } }];
}

return [{
  json: { ...$('Extract Drive File ID').item.json, skipTranscription: false },
  binary: $input.item.binary
}];

